(6,0,'2026-04-11 16:07:28','2026-04-11 14:07:28','<!--\n    SOMA Avignon — Contenu Page d\'Accueil\n    À copier-coller dans l\'éditeur WordPress (mode Code/HTML)\n    pour la page définie comme \"Page d\'accueil statique\"\n    Theme: Child Astra — SOMA Avignon v2.0\n-->\n\n<!-- HERO SPLIT — Texte à gauche, photo à droite\n     ⚠ Remplacez /wp-content/themes/soma-avignon/img/preview.webp par l\'URL\n     de votre photo uploadée dans Médias → Ajouter.\n-->\n<!-- wp:html -->\n<section class=\"soma-hero-split\">\n    <div class=\"soma-hero-split__text\">\n        <p class=\"soma-subtitle\">Bien-être &amp; Sérénité</p>\n        <h1>Massage énergétique crânien &amp; Coiffure <em>à Avignon</em></h1>\n        <div class=\"soma-hero-split__line\"></div>\n        <p class=\"soma-hero-split__desc\">Un espace dédié à votre bien-être, où le soin du corps et de l\'esprit se rencontrent dans une approche holistique et bienveillante.</p>\n        <div class=\"soma-hero-split__buttons\">\n            <a href=\"#\" class=\"wp-block-button__link soma-rdv-btn\">Prendre rendez-vous</a>\n            <a href=\"#prestations\" class=\"soma-hero-split__link\">Découvrir nos soins &rarr;</a>\n        </div>\n    </div>\n    <div class=\"soma-hero-split__image\">\n        <div class=\"soma-hero-split__frame\">\n            <img src=\"/wp-content/themes/soma-avignon/img/preview.webp\" alt=\"SOMA Avignon — Espace bien-être\" loading=\"eager\"/>\n        </div>\n        <div class=\"soma-hero-split__deco soma-hero-split__deco--circle\"></div>\n        <div class=\"soma-hero-split__deco soma-hero-split__deco--dots\"></div>\n    </div>\n</section>\n<!-- /wp:html -->\n\n<!-- BANDEAU DÉFILANT -->\n<!-- wp:shortcode -->\n[soma_marquee items=\"Massage énergétique crânien,Bien-être holistique,Coiffure,Soins sur mesure,Reconnexion à soi,Avignon\"]\n<!-- /wp:shortcode -->\n\n<!-- PRÉSENTATION RAPIDE -->\n<!-- wp:group {\"className\":\"soma-section soma-section-white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-white\">\n    <!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n    <div class=\"wp-block-columns are-vertically-aligned-center\">\n        <!-- wp:column {\"verticalAlignment\":\"center\",\"className\":\"soma-fade-in-left\"} -->\n        <div class=\"wp-block-column is-vertically-aligned-center soma-fade-in-left\">\n            <!-- wp:image {\"sizeSlug\":\"large\",\"className\":\"soma-about-img\"} -->\n            <figure class=\"wp-block-image size-large soma-about-img\">\n                <img src=\"/wp-content/themes/soma-avignon/img/preview3.webp\" alt=\"Espace de soin SOMA Avignon\"/>\n            </figure>\n            <!-- /wp:image -->\n        </div>\n        <!-- /wp:column -->\n\n        <!-- wp:column {\"verticalAlignment\":\"center\",\"className\":\"soma-fade-in-right\"} -->\n        <div class=\"wp-block-column is-vertically-aligned-center soma-fade-in-right\">\n            <!-- wp:paragraph {\"className\":\"soma-subtitle\"} -->\n            <p class=\"soma-subtitle\">Bienvenue</p>\n            <!-- /wp:paragraph -->\n\n            <!-- wp:heading {\"level\":2} -->\n            <h2 class=\"wp-block-heading\">Un soin pour le corps<br>et l\'esprit</h2>\n            <!-- /wp:heading -->\n\n            <!-- wp:separator {\"className\":\"soma-divider\"} -->\n            <hr class=\"wp-block-separator has-alpha-channel-opacity soma-divider\" style=\"margin-left:0!important;\"/>\n            <!-- /wp:separator -->\n\n            <!-- wp:paragraph -->\n            <p>Praticienne en massage énergétique crânien et coiffeuse, je vous accueille dans un espace chaleureux à Avignon pour des soins personnalisés qui allient bien-être et beauté.</p>\n            <!-- /wp:paragraph -->\n\n            <!-- wp:paragraph -->\n            <p>Chaque soin est un moment unique de détente et de reconnexion, adapté à vos besoins. Que ce soit pour un massage crânien, un soin prénatal ou postnatal, je vous accompagne avec douceur et bienveillance.</p>\n            <!-- /wp:paragraph -->\n\n            <!-- wp:buttons -->\n            <div class=\"wp-block-buttons\">\n                <!-- wp:button {\"className\":\"is-style-outline\"} -->\n                <div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link wp-element-button\" href=\"/a-propos/\">En savoir plus</a></div>\n                <!-- /wp:button -->\n            </div>\n            <!-- /wp:buttons -->\n        </div>\n        <!-- /wp:column -->\n    </div>\n    <!-- /wp:columns -->\n</div>\n<!-- /wp:group -->\n\n<!-- PRESTATIONS -->\n<!-- wp:group {\"className\":\"soma-section soma-section-beige\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-beige\" id=\"prestations\">\n    <!-- wp:paragraph {\"align\":\"center\",\"className\":\"soma-subtitle\"} -->\n    <p class=\"has-text-align-center soma-subtitle\">Nos soins</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":2} -->\n    <h2 class=\"wp-block-heading has-text-align-center\">Prestations &amp; Rituels</h2>\n    <!-- /wp:heading -->\n\n    <!-- wp:separator {\"className\":\"soma-divider\"} -->\n    <hr class=\"wp-block-separator has-alpha-channel-opacity soma-divider\"/>\n    <!-- /wp:separator -->\n\n    <!-- wp:paragraph {\"align\":\"center\"} -->\n    <p class=\"has-text-align-center\">Des soins sur mesure pour accompagner votre bien-être au quotidien.</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:shortcode -->\n    [soma_prestations limit=\"3\"]\n    <!-- /wp:shortcode -->\n\n    <!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"},\"style\":{\"spacing\":{\"margin\":{\"top\":\"2.5rem\"}}}} -->\n    <div class=\"wp-block-buttons\" style=\"margin-top:2.5rem\">\n        <!-- wp:button {\"className\":\"is-style-outline\"} -->\n        <div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link wp-element-button\" href=\"/prestations/\">Voir toutes les prestations</a></div>\n        <!-- /wp:button -->\n    </div>\n    <!-- /wp:buttons -->\n</div>\n<!-- /wp:group -->\n\n<!-- COMPTEURS / CHIFFRES CLÉS -->\n<!-- wp:group {\"className\":\"soma-section soma-section-terracotta\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-terracotta\">\n    <!-- wp:paragraph {\"align\":\"center\",\"className\":\"soma-subtitle\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"rgba(255,255,255,0.7)\"}}}}} -->\n    <p class=\"has-text-align-center soma-subtitle\" style=\"color:rgba(255,255,255,0.7)!important;\">En quelques chiffres</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":2} -->\n    <h2 class=\"wp-block-heading has-text-align-center\">Notre engagement envers vous</h2>\n    <!-- /wp:heading -->\n\n    <!-- wp:shortcode -->\n    [soma_stats items=\"500+|Clientes accompagnées,5|Années d\'expérience,15+|Soins proposés,100%|Bienveillance\"]\n    <!-- /wp:shortcode -->\n</div>\n<!-- /wp:group -->\n\n<!-- CITATION -->\n<!-- wp:group {\"className\":\"soma-section soma-section-white soma-fade-in\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-white soma-fade-in\">\n    <!-- wp:html -->\n    <p class=\"soma-big-quote\">Le vrai voyage de découverte ne consiste pas à chercher de nouveaux paysages, mais à avoir de nouveaux yeux.</p>\n    <p style=\"text-align:center;font-size:0.85rem;color:var(--soma-camel-dark);font-weight:500;letter-spacing:0.05em;\">— Marcel Proust</p>\n    <!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n<!-- TÉMOIGNAGES -->\n<!-- wp:group {\"className\":\"soma-section soma-section-beige soma-fade-in\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-beige soma-fade-in\">\n    <!-- wp:paragraph {\"align\":\"center\",\"className\":\"soma-subtitle\"} -->\n    <p class=\"has-text-align-center soma-subtitle\">Témoignages</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":2} -->\n    <h2 class=\"wp-block-heading has-text-align-center\">Ce que disent nos client(e)s</h2>\n    <!-- /wp:heading -->\n\n    <!-- wp:separator {\"className\":\"soma-divider\"} -->\n    <hr class=\"wp-block-separator has-alpha-channel-opacity soma-divider\"/>\n    <!-- /wp:separator -->\n\n    <!-- wp:shortcode -->\n    [soma_temoignages limit=\"3\"]\n    <!-- /wp:shortcode -->\n</div>\n<!-- /wp:group -->\n\n<!-- CTA RÉSERVATION -->\n<!-- wp:group {\"className\":\"soma-section soma-section-terracotta\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-terracotta\">\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":2} -->\n    <h2 class=\"wp-block-heading has-text-align-center\">Prêt(e) à prendre soin de vous ?</h2>\n    <!-- /wp:heading -->\n\n    <!-- wp:paragraph {\"align\":\"center\"} -->\n    <p class=\"has-text-align-center\">Réservez votre séance et offrez-vous un moment de détente et de reconnexion.</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n    <div class=\"wp-block-buttons\">\n        <!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#c47a5a\"}}} -->\n        <div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#c47a5a;background-color:#ffffff\">Réserver maintenant</a></div>\n        <!-- /wp:button -->\n    </div>\n    <!-- /wp:buttons -->\n</div>\n<!-- /wp:group -->\n\n<!-- COLLABORATION ATELIER SOMA -->\n<!-- wp:group {\"className\":\"soma-section soma-section-white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-white\">\n    <!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n    <div class=\"wp-block-columns are-vertically-aligned-center\">\n        <!-- wp:column {\"verticalAlignment\":\"center\",\"className\":\"soma-fade-in-left\"} -->\n        <div class=\"wp-block-column is-vertically-aligned-center soma-fade-in-left\">\n            <!-- wp:paragraph {\"className\":\"soma-subtitle\"} -->\n            <p class=\"soma-subtitle\">Collaboration</p>\n            <!-- /wp:paragraph -->\n\n            <!-- wp:heading {\"level\":2} -->\n            <h2 class=\"wp-block-heading\">En partenariat avec<br>Atelier SOMA</h2>\n            <!-- /wp:heading -->\n\n            <!-- wp:separator {\"className\":\"soma-divider\"} -->\n            <hr class=\"wp-block-separator has-alpha-channel-opacity soma-divider\" style=\"margin-left:0!important;\"/>\n            <!-- /wp:separator -->\n\n            <!-- wp:paragraph -->\n            <p>Notre collaboration avec Atelier SOMA à Boulogne-Billancourt nous permet de partager une vision commune du bien-être holistique. Découvrez comment nos pratiques se complètent pour vous offrir une expérience complète de soin et de transformation.</p>\n            <!-- /wp:paragraph -->\n\n            <!-- wp:buttons -->\n            <div class=\"wp-block-buttons\">\n                <!-- wp:button {\"className\":\"is-style-outline\"} -->\n                <div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link wp-element-button\" href=\"/collaboration-atelier-soma/\">Découvrir la collaboration</a></div>\n                <!-- /wp:button -->\n            </div>\n            <!-- /wp:buttons -->\n        </div>\n        <!-- /wp:column -->\n\n        <!-- wp:column {\"verticalAlignment\":\"center\",\"className\":\"soma-fade-in-right\"} -->\n        <div class=\"wp-block-column is-vertically-aligned-center soma-fade-in-right\">\n            <!-- wp:image {\"sizeSlug\":\"large\",\"className\":\"soma-about-img\"} -->\n            <figure class=\"wp-block-image size-large soma-about-img\">\n                <img src=\"/wp-content/themes/soma-avignon/img/preview4.webp\" alt=\"Collaboration Atelier SOMA\"/>\n            </figure>\n            <!-- /wp:image -->\n        </div>\n        <!-- /wp:column -->\n    </div>\n    <!-- /wp:columns -->\n</div>\n<!-- /wp:group -->','Accueil','','publish','closed','closed','','accueil','','','2026-04-11 19:23:55','2026-04-11 17:23:55','',0,'http://localhost:8090/?page_id=6',0,'page','',0),
(7,0,'2026-04-11 16:07:28','2026-04-11 14:07:28','<!--\n    SOMA Avignon — Contenu Page Prestations\n    À copier-coller dans l\'éditeur WordPress (mode Code/HTML)\n    Theme: Child Astra — SOMA Avignon v2.0\n-->\n\n<!-- HEADER -->\n<!-- wp:group {\"className\":\"soma-page-header\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-page-header\">\n    <!-- wp:paragraph {\"align\":\"center\",\"className\":\"soma-subtitle\"} -->\n    <p class=\"has-text-align-center soma-subtitle\">Nos soins</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":1} -->\n    <h1 class=\"wp-block-heading has-text-align-center\">Prestations &amp; Rituels</h1>\n    <!-- /wp:heading -->\n\n    <!-- wp:separator {\"className\":\"soma-divider\"} -->\n    <hr class=\"wp-block-separator has-alpha-channel-opacity soma-divider\"/>\n    <!-- /wp:separator -->\n\n    <!-- wp:paragraph {\"align\":\"center\"} -->\n    <p class=\"has-text-align-center\">Des soins holistiques pour prendre soin de vous en profondeur.<br>Chaque prestation est personnalisée selon vos besoins.</p>\n    <!-- /wp:paragraph -->\n</div>\n<!-- /wp:group -->\n\n<!-- TOUTES LES PRESTATIONS -->\n<!-- wp:group {\"className\":\"soma-section soma-section-white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-white\">\n    <!-- wp:shortcode -->\n    [soma_prestations limit=\"12\"]\n    <!-- /wp:shortcode -->\n</div>\n<!-- /wp:group -->\n\n<!-- APPROCHE -->\n<!-- wp:group {\"className\":\"soma-section soma-section-beige soma-fade-in\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-beige soma-fade-in\">\n    <!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n    <div class=\"wp-block-columns are-vertically-aligned-center\">\n        <!-- wp:column {\"verticalAlignment\":\"center\"} -->\n        <div class=\"wp-block-column is-vertically-aligned-center\">\n            <!-- wp:paragraph {\"className\":\"soma-subtitle\"} -->\n            <p class=\"soma-subtitle\">Notre approche</p>\n            <!-- /wp:paragraph -->\n\n            <!-- wp:heading {\"level\":2} -->\n            <h2 class=\"wp-block-heading\">Un soin adapté à chaque personne</h2>\n            <!-- /wp:heading -->\n\n            <!-- wp:paragraph -->\n            <p>Chaque séance commence par un temps d\'échange pour comprendre vos besoins et vos attentes. Le soin est ensuite adapté en conséquence, dans le respect de votre corps et de votre rythme.</p>\n            <!-- /wp:paragraph -->\n\n            <!-- wp:paragraph -->\n            <p>Que vous cherchiez un moment de détente profonde, un soulagement de tensions spécifiques, ou un accompagnement dans une période de transition, nous trouvons ensemble la réponse la plus juste.</p>\n            <!-- /wp:paragraph -->\n        </div>\n        <!-- /wp:column -->\n\n        <!-- wp:column {\"verticalAlignment\":\"center\"} -->\n        <div class=\"wp-block-column is-vertically-aligned-center\">\n            <!-- wp:image {\"sizeSlug\":\"large\",\"className\":\"soma-about-img\"} -->\n            <figure class=\"wp-block-image size-large soma-about-img\">\n                <img src=\"/wp-content/themes/soma-avignon/img/preview5.webp\" alt=\"Approche holistique SOMA Avignon\"/>\n            </figure>\n            <!-- /wp:image -->\n        </div>\n        <!-- /wp:column -->\n    </div>\n    <!-- /wp:columns -->\n</div>\n<!-- /wp:group -->\n\n<!-- CTA -->\n<!-- wp:group {\"className\":\"soma-section soma-section-terracotta\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-terracotta\">\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":2} -->\n    <h2 class=\"wp-block-heading has-text-align-center\">Réservez votre séance</h2>\n    <!-- /wp:heading -->\n\n    <!-- wp:paragraph {\"align\":\"center\"} -->\n    <p class=\"has-text-align-center\">Choisissez votre soin et trouvez le créneau qui vous convient.</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n    <div class=\"wp-block-buttons\">\n        <!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#c47a5a\"}}} -->\n        <div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#c47a5a;background-color:#ffffff\">Prendre rendez-vous</a></div>\n        <!-- /wp:button -->\n    </div>\n    <!-- /wp:buttons -->\n</div>\n<!-- /wp:group -->','Prestations & Rituels','','publish','closed','closed','','prestations','','','2026-04-11 19:23:55','2026-04-11 17:23:55','',0,'http://localhost:8090/?page_id=7',0,'page','',0),
(8,0,'2026-04-11 16:07:28','2026-04-11 14:07:28','<!--\n    SOMA Avignon — Contenu Page Collaboration Atelier SOMA\n    À copier-coller dans l\'éditeur WordPress (mode Code/HTML)\n    Theme: Child Astra — SOMA Avignon v2.0\n-->\n\n<!-- HEADER -->\n<!-- wp:group {\"className\":\"soma-page-header\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-page-header\">\n    <!-- wp:paragraph {\"align\":\"center\",\"className\":\"soma-subtitle\"} -->\n    <p class=\"has-text-align-center soma-subtitle\">Partenariat</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":1} -->\n    <h1 class=\"wp-block-heading has-text-align-center\">Collaboration avec Atelier SOMA</h1>\n    <!-- /wp:heading -->\n\n    <!-- wp:separator {\"className\":\"soma-divider\"} -->\n    <hr class=\"wp-block-separator has-alpha-channel-opacity soma-divider\"/>\n    <!-- /wp:separator -->\n\n    <!-- wp:paragraph {\"align\":\"center\"} -->\n    <p class=\"has-text-align-center\">Deux espaces, une même philosophie du bien-être et de la reconnexion à soi.</p>\n    <!-- /wp:paragraph -->\n</div>\n<!-- /wp:group -->\n\n<!-- CONTENU PRINCIPAL -->\n<!-- wp:group {\"className\":\"soma-section soma-section-white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-white\">\n    <!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n    <div class=\"wp-block-columns are-vertically-aligned-center\">\n        <!-- wp:column {\"verticalAlignment\":\"center\",\"className\":\"soma-fade-in-left\"} -->\n        <div class=\"wp-block-column is-vertically-aligned-center soma-fade-in-left\">\n            <!-- wp:image {\"sizeSlug\":\"large\",\"className\":\"soma-about-img\"} -->\n            <figure class=\"wp-block-image size-large soma-about-img\">\n                <img src=\"/wp-content/themes/soma-avignon/img/preview2.webp\" alt=\"Atelier SOMA Boulogne-Billancourt\"/>\n            </figure>\n            <!-- /wp:image -->\n        </div>\n        <!-- /wp:column -->\n\n        <!-- wp:column {\"verticalAlignment\":\"center\",\"className\":\"soma-fade-in-right\"} -->\n        <div class=\"wp-block-column is-vertically-aligned-center soma-fade-in-right\">\n            <!-- wp:heading {\"level\":2} -->\n            <h2 class=\"wp-block-heading\">L\'Atelier SOMA</h2>\n            <!-- /wp:heading -->\n\n            <!-- wp:separator {\"className\":\"soma-divider\"} -->\n            <hr class=\"wp-block-separator has-alpha-channel-opacity soma-divider\" style=\"margin-left:0!important;\"/>\n            <!-- /wp:separator -->\n\n            <!-- wp:paragraph -->\n            <p>L\'Atelier SOMA, fondé à Boulogne-Billancourt, est un espace de soin holistique dédié au bien-être des femmes. Porté par une approche globale mêlant massages, rituels et accompagnement, c\'est un lieu de transformation et de reconnexion à soi.</p>\n            <!-- /wp:paragraph -->\n\n            <!-- wp:paragraph -->\n            <p>Notre antenne à Avignon s\'inscrit dans cette même philosophie : offrir un espace chaleureux où chaque soin est pensé pour répondre à vos besoins profonds, dans le respect et la bienveillance.</p>\n            <!-- /wp:paragraph -->\n        </div>\n        <!-- /wp:column -->\n    </div>\n    <!-- /wp:columns -->\n</div>\n<!-- /wp:group -->\n\n<!-- CITATION -->\n<!-- wp:group {\"className\":\"soma-section soma-section-beige soma-fade-in\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-beige soma-fade-in\">\n    <!-- wp:html -->\n    <p class=\"soma-big-quote\">Prendre soin de soi n\'est pas de la vanité, c\'est de la survie.</p>\n    <p style=\"text-align:center;font-size:0.85rem;color:var(--soma-camel-dark);font-weight:500;letter-spacing:0.05em;\">— Audre Lorde</p>\n    <!-- /wp:html -->\n</div>\n<!-- /wp:group -->\n\n<!-- VALEURS PARTAGÉES -->\n<!-- wp:group {\"className\":\"soma-section soma-section-white soma-fade-in\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-white soma-fade-in\">\n    <!-- wp:paragraph {\"align\":\"center\",\"className\":\"soma-subtitle\"} -->\n    <p class=\"has-text-align-center soma-subtitle\">Ce qui nous unit</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":2} -->\n    <h2 class=\"wp-block-heading has-text-align-center\">Nos valeurs partagées</h2>\n    <!-- /wp:heading -->\n\n    <!-- wp:separator {\"className\":\"soma-divider\"} -->\n    <hr class=\"wp-block-separator has-alpha-channel-opacity soma-divider\"/>\n    <!-- /wp:separator -->\n\n    <!-- wp:columns {\"className\":\"soma-values soma-stagger\"} -->\n    <div class=\"wp-block-columns soma-values soma-stagger\">\n        <!-- wp:column -->\n        <div class=\"wp-block-column\" style=\"text-align:center;\">\n            <!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"style\":{\"typography\":{\"fontSize\":\"2.5rem\"}}} -->\n            <h3 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2.5rem\">&#10023;</h3>\n            <!-- /wp:heading -->\n\n            <!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n            <h4 class=\"wp-block-heading has-text-align-center\">Bienveillance</h4>\n            <!-- /wp:heading -->\n\n            <!-- wp:paragraph {\"align\":\"center\"} -->\n            <p class=\"has-text-align-center\">Chaque personne est accueillie avec douceur et sans jugement, dans un espace de confiance.</p>\n            <!-- /wp:paragraph -->\n        </div>\n        <!-- /wp:column -->\n\n        <!-- wp:column -->\n        <div class=\"wp-block-column\" style=\"text-align:center;\">\n            <!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"style\":{\"typography\":{\"fontSize\":\"2.5rem\"}}} -->\n            <h3 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2.5rem\">&#10043;</h3>\n            <!-- /wp:heading -->\n\n            <!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n            <h4 class=\"wp-block-heading has-text-align-center\">Holistique</h4>\n            <!-- /wp:heading -->\n\n            <!-- wp:paragraph {\"align\":\"center\"} -->\n            <p class=\"has-text-align-center\">Une approche globale qui prend en compte le corps, l\'esprit et les émotions.</p>\n            <!-- /wp:paragraph -->\n        </div>\n        <!-- /wp:column -->\n\n        <!-- wp:column -->\n        <div class=\"wp-block-column\" style=\"text-align:center;\">\n            <!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"style\":{\"typography\":{\"fontSize\":\"2.5rem\"}}} -->\n            <h3 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2.5rem\">&#9672;</h3>\n            <!-- /wp:heading -->\n\n            <!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n            <h4 class=\"wp-block-heading has-text-align-center\">Authenticité</h4>\n            <!-- /wp:heading -->\n\n            <!-- wp:paragraph {\"align\":\"center\"} -->\n            <p class=\"has-text-align-center\">Des soins sincères, adaptés à chaque personne, dans le respect de son parcours unique.</p>\n            <!-- /wp:paragraph -->\n        </div>\n        <!-- /wp:column -->\n    </div>\n    <!-- /wp:columns -->\n</div>\n<!-- /wp:group -->\n\n<!-- COMPTEURS -->\n<!-- wp:group {\"className\":\"soma-section soma-section-beige\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-beige\">\n    <!-- wp:shortcode -->\n    [soma_stats items=\"2|Espaces de soin,1|Vision commune,500+|Clientes accompagnées,100%|Engagement\"]\n    <!-- /wp:shortcode -->\n</div>\n<!-- /wp:group -->\n\n<!-- LIEN VERS ATELIER SOMA -->\n<!-- wp:group {\"className\":\"soma-section soma-section-terracotta\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-terracotta\">\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":2} -->\n    <h2 class=\"wp-block-heading has-text-align-center\">Découvrez l\'Atelier SOMA</h2>\n    <!-- /wp:heading -->\n\n    <!-- wp:paragraph {\"align\":\"center\"} -->\n    <p class=\"has-text-align-center\">Visitez le site de notre partenaire pour découvrir l\'ensemble des soins et rituels proposés à Boulogne-Billancourt.</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n    <div class=\"wp-block-buttons\">\n        <!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#c47a5a\"}}} -->\n        <div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#c47a5a;background-color:#ffffff\" href=\"https://www.ateliersoma.fr/\" target=\"_blank\" rel=\"noopener noreferrer\">Visiter ateliersoma.fr</a></div>\n        <!-- /wp:button -->\n    </div>\n    <!-- /wp:buttons -->\n</div>\n<!-- /wp:group -->','Collaboration Atelier SOMA','','publish','closed','closed','','collaboration-atelier-soma','','','2026-04-11 19:23:56','2026-04-11 17:23:56','',0,'http://localhost:8090/?page_id=8',0,'page','',0),
(9,0,'2026-04-11 16:07:29','2026-04-11 14:07:29','<!--\n    SOMA Avignon — Contenu Page Contact / Informations\n    À copier-coller dans l\'éditeur WordPress (mode Code/HTML)\n    Plugin recommandé: Contact Form 7 (pour le formulaire)\n    Theme: Child Astra — SOMA Avignon v2.0\n-->\n\n<!-- HEADER -->\n<!-- wp:group {\"className\":\"soma-page-header\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-page-header\">\n    <!-- wp:paragraph {\"align\":\"center\",\"className\":\"soma-subtitle\"} -->\n    <p class=\"has-text-align-center soma-subtitle\">Contact</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":1} -->\n    <h1 class=\"wp-block-heading has-text-align-center\">Nous contacter</h1>\n    <!-- /wp:heading -->\n\n    <!-- wp:separator {\"className\":\"soma-divider\"} -->\n    <hr class=\"wp-block-separator has-alpha-channel-opacity soma-divider\"/>\n    <!-- /wp:separator -->\n\n    <!-- wp:paragraph {\"align\":\"center\"} -->\n    <p class=\"has-text-align-center\">N\'hésitez pas à nous écrire ou à nous appeler pour toute question.</p>\n    <!-- /wp:paragraph -->\n</div>\n<!-- /wp:group -->\n\n<!-- INFOS DE CONTACT -->\n<!-- wp:group {\"className\":\"soma-section soma-section-white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-white\">\n    <!-- wp:shortcode -->\n    [soma_contact_info]\n    <!-- /wp:shortcode -->\n</div>\n<!-- /wp:group -->\n\n<!-- RÉSEAUX SOCIAUX -->\n<!-- wp:group {\"className\":\"soma-section soma-section-white soma-fade-in\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-white soma-fade-in\">\n    <!-- wp:paragraph {\"align\":\"center\",\"className\":\"soma-subtitle\"} -->\n    <p class=\"has-text-align-center soma-subtitle\">Communauté</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":2} -->\n    <h2 class=\"wp-block-heading has-text-align-center\">Suivez-nous</h2>\n    <!-- /wp:heading -->\n\n    <!-- wp:separator {\"className\":\"soma-divider\"} -->\n    <hr class=\"wp-block-separator has-alpha-channel-opacity soma-divider\"/>\n    <!-- /wp:separator -->\n\n    <!-- wp:paragraph {\"align\":\"center\"} -->\n    <p class=\"has-text-align-center\">Retrouvez-nous sur Instagram pour découvrir nos soins et notre univers au quotidien.</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:shortcode -->\n    [soma_social_links]\n    <!-- /wp:shortcode -->\n</div>\n<!-- /wp:group -->\n\n<!-- CTA -->\n<!-- wp:group {\"className\":\"soma-section soma-section-terracotta\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-section soma-section-terracotta\">\n    <!-- wp:heading {\"textAlign\":\"center\",\"level\":2} -->\n    <h2 class=\"wp-block-heading has-text-align-center\">Envie de prendre rendez-vous ?</h2>\n    <!-- /wp:heading -->\n\n    <!-- wp:paragraph {\"align\":\"center\"} -->\n    <p class=\"has-text-align-center\">Choisissez votre créneau et offrez-vous un moment rien qu\'à vous.</p>\n    <!-- /wp:paragraph -->\n\n    <!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n    <div class=\"wp-block-buttons\">\n        <!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#c47a5a\"}}} -->\n        <div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#c47a5a;background-color:#ffffff\">Prendre rendez-vous</a></div>\n        <!-- /wp:button -->\n    </div>\n    <!-- /wp:buttons -->\n</div>\n<!-- /wp:group -->','Contact','','publish','closed','closed','','contact','','','2026-04-11 19:23:56','2026-04-11 17:23:56','',0,'http://localhost:8090/?page_id=9',0,'page','',0),
(15,0,'2026-04-11 16:08:03','2026-04-11 14:08:03','','Massage Énergétique Crânien','Un soin profond et apaisant qui libère les tensions du crâne et rééquilibre les énergies du corps. Idéal pour le stress, les migraines et le lâcher-prise.','publish','closed','closed','','massage-energetique-cranien','','','2026-04-11 16:08:03','2026-04-11 14:08:03','',0,'http://localhost:8090/?prestation=massage-energetique-cranien',0,'prestation','',0),
(16,0,'2026-04-11 16:08:03','2026-04-11 14:08:03','','Massage Prénatal','Un massage doux et enveloppant, spécialement conçu pour accompagner les futures mamans dans leur grossesse avec sérénité et confort.','publish','closed','closed','','massage-prenatal','','','2026-04-11 16:08:03','2026-04-11 14:08:03','',0,'http://localhost:8090/?prestation=massage-prenatal',0,'prestation','',0),
(17,0,'2026-04-11 16:08:04','2026-04-11 14:08:04','','Massage Postnatal','Un soin de reconnexion après l accouchement pour aider le corps à retrouver son équilibre et offrir un moment de détente bien mérité.','publish','closed','closed','','massage-postnatal','','','2026-04-11 16:08:04','2026-04-11 14:08:04','',0,'http://localhost:8090/?prestation=massage-postnatal',0,'prestation','',0),
(18,0,'2026-04-11 16:08:05','2026-04-11 14:08:05','Un moment de pure détente. Le massage crânien m a permis de relâcher toutes mes tensions. Je me suis sentie comme sur un nuage. Je recommande les yeux fermés !','Marie L.','','publish','closed','closed','','marie-l','','','2026-04-11 16:08:05','2026-04-11 14:08:05','',0,'http://localhost:8090/?temoignage=marie-l',0,'temoignage','',0),
(19,0,'2026-04-11 16:08:06','2026-04-11 14:08:06','Le massage prénatal a été une vraie bulle de douceur pendant ma grossesse. L approche bienveillante et le cadre chaleureux font toute la différence.','Sophie D.','','publish','closed','closed','','sophie-d','','','2026-04-11 16:08:06','2026-04-11 14:08:06','',0,'http://localhost:8090/?temoignage=sophie-d',0,'temoignage','',0),
(20,0,'2026-04-11 16:08:06','2026-04-11 14:08:06','Je reviens régulièrement pour le massage énergétique crânien. C est devenu mon rituel bien-être indispensable. Merci pour ces moments de reconnexion.','Camille R.','','publish','closed','closed','','camille-r','','','2026-04-11 16:08:06','2026-04-11 14:08:06','',0,'http://localhost:8090/?temoignage=camille-r',0,'temoignage','',0),
