(22,0,'2026-04-11 16:21:21','2026-04-11 14:21:21','<!-- wp:cover {\"dimRatio\":60,\"minHeight\":90,\"minHeightUnit\":\"vh\",\"isDark\":true,\"className\":\"soma-hero\",\"style\":{\"color\":{\"background\":\"#3D3029\"}}} -->\n<div class=\"wp-block-cover is-dark soma-hero\" style=\"min-height:90vh\"><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim-60 has-background-dim\" style=\"background-color:#3D3029\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"0.9rem\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.2em\"},\"color\":{\"text\":\"#C4A882\"}}} -->\n<p style=\"color:#C4A882;font-size:0.9rem;text-transform:uppercase;letter-spacing:0.2em\">Bien-être &amp; Sérénité</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":1,\"style\":{\"typography\":{\"fontSize\":\"3.2rem\"},\"color\":{\"text\":\"#ffffff\"}}} -->\n<h1 class=\"wp-block-heading\" style=\"color:#ffffff;font-size:3.2rem\">Massage énergétique crânien &amp; Coiffure à Avignon</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#ffffffcc\"},\"typography\":{\"fontSize\":\"1.1rem\"}}} -->\n<p style=\"color:#ffffffcc;font-size:1.1rem\">Un espace dédié à votre bien-être, où le soin du corps et de l esprit se rencontrent dans une approche holistique et bienveillante.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#C47A5A\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" style=\"background-color:#C47A5A\">Prendre un rendez-vous</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"className\":\"is-style-outline\",\"style\":{\"color\":{\"text\":\"#ffffff\"},\"border\":{\"color\":\"#ffffff\",\"width\":\"1px\"}}} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link has-text-color has-border-color wp-element-button\" style=\"color:#ffffff;border-color:#ffffff;border-width:1px\" href=\"#prestations\">Découvrir nos soins</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div></div>\n<!-- /wp:cover -->\n\n<!-- wp:spacer {\"height\":\"40px\"} -->\n<div style=\"height:40px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" id=\"prestations\" style=\"padding-top:4rem;padding-bottom:4rem\"><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"0.85rem\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.2em\"},\"color\":{\"text\":\"#C47A5A\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#C47A5A;font-size:0.85rem;text-transform:uppercase;letter-spacing:0.2em\">Nos soins</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Prestations &amp; Rituels</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">Des soins sur mesure pour accompagner votre bien-être au quotidien.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:shortcode -->\n[soma_prestations limit=\"3\"]\n<!-- /wp:shortcode -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"},\"style\":{\"spacing\":{\"margin\":{\"top\":\"2rem\"}}}} -->\n<div class=\"wp-block-buttons\" style=\"margin-top:2rem\"><!-- wp:button {\"className\":\"is-style-outline\",\"style\":{\"color\":{\"text\":\"#C47A5A\"},\"border\":{\"color\":\"#C47A5A\"}}} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link has-text-color has-border-color wp-element-button\" style=\"color:#C47A5A;border-color:#C47A5A\" href=\"/prestations/\">Voir toutes les prestations</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:4rem;padding-bottom:4rem\"><!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:image {\"sizeSlug\":\"large\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"/wp-content/themes/soma-avignon/img/preview3.webp\" alt=\"Massage crânien SOMA Avignon\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"0.85rem\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.2em\"},\"color\":{\"text\":\"#C47A5A\"}}} -->\n<p style=\"color:#C47A5A;font-size:0.85rem;text-transform:uppercase;letter-spacing:0.2em\">À propos</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Un soin pour le corps et l esprit</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">Praticienne en massage énergétique crânien et coiffeuse, je vous accueille dans un espace chaleureux à Avignon pour des soins personnalisés qui allient bien-être et beauté.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">Chaque soin est un moment unique de détente et de reconnexion, adapté à vos besoins. Que ce soit pour un massage crânien, un soin prénatal ou postnatal, je vous accompagne avec douceur et bienveillance.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"className\":\"is-style-outline\",\"style\":{\"color\":{\"text\":\"#C47A5A\"},\"border\":{\"color\":\"#C47A5A\"}}} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link has-text-color has-border-color wp-element-button\" style=\"color:#C47A5A;border-color:#C47A5A\" href=\"/contact/\">En savoir plus</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"padding-top:4rem;padding-bottom:4rem\"><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"0.85rem\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.2em\"},\"color\":{\"text\":\"#C47A5A\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#C47A5A;font-size:0.85rem;text-transform:uppercase;letter-spacing:0.2em\">Témoignages</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Ce que disent nos client(e)s</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:shortcode -->\n[soma_temoignages limit=\"3\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#C47A5A\",\"text\":\"#ffffff\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-text-color has-background\" style=\"color:#ffffff;background-color:#C47A5A;padding-top:4rem;padding-bottom:4rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff\">Prêt(e) à prendre soin de vous ?</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffffcc\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#ffffffcc\">Réservez votre séance et offrez-vous un moment de détente et de reconnexion.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#C47A5A\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#C47A5A;background-color:#ffffff\">Réserver maintenant</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#B8964E\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" style=\"background-color:#B8964E\" href=\"#\" target=\"_blank\" rel=\"noreferrer noopener\">Payer en ligne</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:4rem;padding-bottom:4rem\"><!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"0.85rem\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.2em\"},\"color\":{\"text\":\"#C47A5A\"}}} -->\n<p style=\"color:#C47A5A;font-size:0.85rem;text-transform:uppercase;letter-spacing:0.2em\">Collaboration</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">En partenariat avec Atelier SOMA</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">Notre collaboration avec Atelier SOMA à Boulogne-Billancourt nous permet de partager une vision commune du bien-être holistique. Découvrez comment nos pratiques se complètent.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"className\":\"is-style-outline\",\"style\":{\"color\":{\"text\":\"#C47A5A\"},\"border\":{\"color\":\"#C47A5A\"}}} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link has-text-color has-border-color wp-element-button\" style=\"color:#C47A5A;border-color:#C47A5A\" href=\"/collaboration-atelier-soma/\">Découvrir la collaboration</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:image {\"sizeSlug\":\"large\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"/wp-content/themes/soma-avignon/img/preview5.webp\" alt=\"Espace SOMA Avignon\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n','Accueil','','inherit','closed','closed','','6-revision-v1','','','2026-04-11 16:21:21','2026-04-11 14:21:21','',6,'http://localhost:8090/?p=22',0,'revision','',0),
(23,0,'2026-04-11 16:21:39','2026-04-11 14:21:39','<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"6rem\",\"bottom\":\"3rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:6rem;padding-bottom:3rem\"><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"0.85rem\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.2em\"},\"color\":{\"text\":\"#C47A5A\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#C47A5A;font-size:0.85rem;text-transform:uppercase;letter-spacing:0.2em\">Nos soins</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":1} -->\n<h1 class=\"wp-block-heading has-text-align-center\">Prestations &amp; Rituels</h1>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">Des soins holistiques pour prendre soin de vous en profondeur. Chaque prestation est personnalisée selon vos besoins.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"padding-top:4rem;padding-bottom:4rem\"><!-- wp:shortcode -->\n[soma_prestations limit=\"12\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:4rem;padding-bottom:4rem\"><!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Paiement en ligne</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">Réglez votre séance en toute sécurité via Stripe.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#B8964E\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" style=\"background-color:#B8964E\" href=\"#\" target=\"_blank\" rel=\"noreferrer noopener\">Payer en ligne via Stripe</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#C47A5A\",\"text\":\"#ffffff\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-text-color has-background\" style=\"color:#ffffff;background-color:#C47A5A;padding-top:4rem;padding-bottom:4rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff\">Réservez votre séance</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffffcc\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#ffffffcc\">Choisissez votre soin et trouvez le créneau qui vous convient.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#C47A5A\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#C47A5A;background-color:#ffffff\">Prendre un rendez-vous</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n','Prestations & Rituels','','inherit','closed','closed','','7-revision-v1','','','2026-04-11 16:21:39','2026-04-11 14:21:39','',7,'http://localhost:8090/?p=23',0,'revision','',0),
(24,0,'2026-04-11 16:22:03','2026-04-11 14:22:03','<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"6rem\",\"bottom\":\"3rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:6rem;padding-bottom:3rem\"><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"0.85rem\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.2em\"},\"color\":{\"text\":\"#C47A5A\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#C47A5A;font-size:0.85rem;text-transform:uppercase;letter-spacing:0.2em\">Partenariat</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":1} -->\n<h1 class=\"wp-block-heading has-text-align-center\">Collaboration avec Atelier SOMA</h1>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">Deux espaces, une même philosophie du bien-être et de la reconnexion à soi.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"padding-top:4rem;padding-bottom:4rem\"><!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:image {\"sizeSlug\":\"large\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"/wp-content/themes/soma-avignon/img/preview4.webp\" alt=\"Bol tibétain SOMA\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:heading -->\n<h2 class=\"wp-block-heading\">L Atelier SOMA</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">L Atelier SOMA, fondé à Boulogne-Billancourt, est un espace de soin holistique dédié au bien-être des femmes. Porté par une approche globale mêlant massages, rituels et accompagnement, c est un lieu de transformation et de reconnexion à soi.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">Notre antenne à Avignon s inscrit dans cette même philosophie : offrir un espace chaleureux où chaque soin est pensé pour répondre à vos besoins profonds, dans le respect et la bienveillance.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:4rem;padding-bottom:4rem\"><!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Nos valeurs partagées</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"style\":{\"typography\":{\"fontSize\":\"2.5rem\"}}} -->\n<h3 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2.5rem\">✧</h3>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n<h4 class=\"wp-block-heading has-text-align-center\">Bienveillance</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">Chaque personne est accueillie avec douceur et sans jugement, dans un espace de confiance.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"style\":{\"typography\":{\"fontSize\":\"2.5rem\"}}} -->\n<h3 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2.5rem\">❋</h3>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n<h4 class=\"wp-block-heading has-text-align-center\">Holistique</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">Une approche globale qui prend en compte le corps, l esprit et les émotions.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"style\":{\"typography\":{\"fontSize\":\"2.5rem\"}}} -->\n<h3 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2.5rem\">◈</h3>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n<h4 class=\"wp-block-heading has-text-align-center\">Authenticité</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">Des soins sincères, adaptés à chaque personne, dans le respect de son parcours unique.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#C47A5A\",\"text\":\"#ffffff\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-text-color has-background\" style=\"color:#ffffff;background-color:#C47A5A;padding-top:4rem;padding-bottom:4rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff\">Découvrez l Atelier SOMA</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffffcc\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#ffffffcc\">Visitez le site de notre partenaire pour découvrir l ensemble des soins et rituels proposés.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#C47A5A\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#C47A5A;background-color:#ffffff\" href=\"https://www.ateliersoma.fr/\" target=\"_blank\" rel=\"noreferrer noopener\">Visiter ateliersoma.fr</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n','Collaboration Atelier SOMA','','inherit','closed','closed','','8-revision-v1','','','2026-04-11 16:22:03','2026-04-11 14:22:03','',8,'http://localhost:8090/?p=24',0,'revision','',0),
(25,0,'2026-04-11 16:22:14','2026-04-11 14:22:14','<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"6rem\",\"bottom\":\"3rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:6rem;padding-bottom:3rem\"><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"0.85rem\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.2em\"},\"color\":{\"text\":\"#C47A5A\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#C47A5A;font-size:0.85rem;text-transform:uppercase;letter-spacing:0.2em\">Contact</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":1} -->\n<h1 class=\"wp-block-heading has-text-align-center\">Nous contacter</h1>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">N hésitez pas à nous écrire ou à nous appeler pour toute question.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"padding-top:4rem;padding-bottom:4rem\"><!-- wp:shortcode -->\n[soma_contact_info]\n<!-- /wp:shortcode --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:4rem;padding-bottom:4rem\"><!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">Suivez-nous</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">Retrouvez-nous sur Instagram pour découvrir nos soins et notre univers au quotidien.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:shortcode -->\n[soma_social_links]\n<!-- /wp:shortcode --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#C47A5A\",\"text\":\"#ffffff\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-text-color has-background\" style=\"color:#ffffff;background-color:#C47A5A;padding-top:4rem;padding-bottom:4rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff\">Envie de prendre rendez-vous ?</h2>\n<!-- /wp:heading -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#C47A5A\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#C47A5A;background-color:#ffffff\">Prendre un rendez-vous</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n','Contact','','inherit','closed','closed','','9-revision-v1','','','2026-04-11 16:22:14','2026-04-11 14:22:14','',9,'http://localhost:8090/?p=25',0,'revision','',0),
(26,0,'2026-04-11 16:26:55','2026-04-11 14:26:55','<!-- HERO BANNIERE — style ateliersoma : titre centré sur image pleine largeur -->\n<!-- wp:cover {\"dimRatio\":50,\"minHeight\":75,\"minHeightUnit\":\"vh\",\"isDark\":true,\"className\":\"soma-hero\",\"style\":{\"color\":{\"background\":\"#3D3029\"}}} -->\n<div class=\"wp-block-cover is-dark soma-hero\" style=\"min-height:75vh\"><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim-50 has-background-dim\" style=\"background-color:#3D3029\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":1,\"style\":{\"typography\":{\"fontSize\":\"2.8rem\",\"letterSpacing\":\"0.06em\"},\"color\":{\"text\":\"#ffffff\"}}} -->\n<h1 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff;font-size:2.8rem;letter-spacing:0.06em\">SOMA AVIGNON</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffffcc\"},\"typography\":{\"fontSize\":\"1.1rem\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#ffffffcc;font-size:1.1rem\">Massage énergétique crânien &amp; Coiffure<br>Un espace de soin et de bien-être à Avignon</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#B8704C\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" style=\"background-color:#B8704C\" href=\"/prestations/\">Consulter nos soins</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"className\":\"is-style-outline\",\"style\":{\"color\":{\"text\":\"#ffffff\"},\"border\":{\"color\":\"#ffffff\",\"width\":\"2px\"}}} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link has-text-color has-border-color wp-element-button\" style=\"color:#ffffff;border-color:#ffffff;border-width:2px\">Prendre un rendez-vous</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div></div>\n<!-- /wp:cover -->\n\n<!-- PRÉSENTATION — 2 images côte à côte + texte descriptif comme ateliersoma -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background soma-intro\" style=\"padding-top:5rem;padding-bottom:5rem\"><!-- wp:columns {\"verticalAlignment\":\"top\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-top\"><!-- wp:column {\"width\":\"45%\",\"verticalAlignment\":\"top\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top\" style=\"flex-basis:45%\"><!-- wp:gallery {\"columns\":2,\"linkTo\":\"none\",\"sizeSlug\":\"medium\"} -->\n<figure class=\"wp-block-gallery has-nested-images columns-2 is-cropped\"><!-- wp:image {\"sizeSlug\":\"medium\"} -->\n<figure class=\"wp-block-image size-medium\"><img src=\"/wp-content/themes/soma-avignon/img/preview.webp\" alt=\"Massage crânien\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"sizeSlug\":\"medium\"} -->\n<figure class=\"wp-block-image size-medium\"><img src=\"/wp-content/themes/soma-avignon/img/preview3.webp\" alt=\"Soin énergétique\"/></figure>\n<!-- /wp:image --></figure>\n<!-- /wp:gallery --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"width\":\"55%\",\"verticalAlignment\":\"top\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top\" style=\"flex-basis:55%\"><!-- wp:heading {\"style\":{\"typography\":{\"fontSize\":\"1.9rem\"}}} -->\n<h2 class=\"wp-block-heading\" style=\"font-size:1.9rem\">SOMA : un espace de soin, de transformation et de reconnexion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bienvenue chez SOMA Avignon, un lieu dédié au bien-être holistique où chaque soin est pensé pour répondre à vos besoins profonds. Praticienne en massage énergétique crânien et coiffeuse, je vous accueille dans un espace chaleureux au coeur d Avignon.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Mes prestations s articulent autour de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Massage énergétique crânien</strong> — libération des tensions, rééquilibrage énergétique</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Massage prénatal</strong> — accompagnement doux de la grossesse</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Massage postnatal</strong> — reconnexion et récupération après l accouchement</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Coiffure holistique</strong> — prendre soin de soi dans sa globalité</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Chaque séance est un moment unique de détente et de reconnexion à soi, dans le respect et la bienveillance.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- SERVICES — Grille de cartes 2x2 comme ateliersoma \"Soins holistiques et rituels\" -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:5rem;padding-bottom:5rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"2rem\",\"letterSpacing\":\"0.08em\",\"textTransform\":\"uppercase\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2rem;letter-spacing:0.08em;text-transform:uppercase\">Soins holistiques &amp; rituels</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:shortcode -->\n[soma_prestations limit=\"4\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:group -->\n\n<!-- LA CARTE — Section tarifs comme ateliersoma -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background soma-carte-section\" style=\"padding-top:5rem;padding-bottom:5rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"2.2rem\",\"letterSpacing\":\"0.12em\",\"textTransform\":\"uppercase\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2.2rem;letter-spacing:0.12em;text-transform:uppercase\">La Carte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">Découvrez sans plus attendre notre carte de soins. Nous faisons en sorte de mobiliser tout notre savoir-faire pour des prestations de qualité.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#B8704C\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" style=\"background-color:#B8704C\" href=\"/prestations/\">Découvrez notre carte</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<!-- TÉMOIGNAGES — comme ateliersoma \"Nos clients témoignent\" -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:5rem;padding-bottom:5rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"2rem\",\"letterSpacing\":\"0.08em\",\"textTransform\":\"uppercase\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2rem;letter-spacing:0.08em;text-transform:uppercase\">Nos client(e)s témoignent</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:shortcode -->\n[soma_temoignages limit=\"3\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:group -->\n\n<!-- CTA RENDEZ-VOUS — bandeau comme ateliersoma -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#B8704C\",\"text\":\"#ffffff\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-text-color has-background\" style=\"color:#ffffff;background-color:#B8704C;padding-top:4rem;padding-bottom:4rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"},\"typography\":{\"fontSize\":\"1.8rem\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff;font-size:1.8rem\">Prêt(e) à prendre soin de vous ?</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffffcc\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#ffffffcc\">Réservez votre séance en ligne ou appelez-nous directement.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#B8704C\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#B8704C;background-color:#ffffff\">Prendre un rendez-vous</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#B8964E\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" style=\"background-color:#B8964E\" href=\"#\" target=\"_blank\" rel=\"noreferrer noopener\">Payer en ligne</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<!-- COLLABORATION ATELIER SOMA — teaser -->\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"padding-top:5rem;padding-bottom:5rem\"><!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"55%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:55%\"><!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"0.8rem\",\"textTransform\":\"uppercase\",\"letterSpacing\":\"0.2em\"},\"color\":{\"text\":\"#B8704C\"}}} -->\n<p style=\"color:#B8704C;font-size:0.8rem;text-transform:uppercase;letter-spacing:0.2em\">En partenariat avec</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"style\":{\"typography\":{\"fontSize\":\"1.9rem\"}}} -->\n<h2 class=\"wp-block-heading\" style=\"font-size:1.9rem\">Atelier SOMA — Boulogne-Billancourt</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">Notre collaboration avec l Atelier SOMA nous permet de partager une vision commune du bien-être holistique et de vous offrir une expérience complète de soin et de transformation.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"className\":\"is-style-outline\",\"style\":{\"color\":{\"text\":\"#B8704C\"},\"border\":{\"color\":\"#B8704C\"}}} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link has-text-color has-border-color wp-element-button\" style=\"color:#B8704C;border-color:#B8704C\" href=\"/collaboration-atelier-soma/\">En savoir plus</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"45%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:45%\"><!-- wp:image {\"sizeSlug\":\"large\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"/wp-content/themes/soma-avignon/img/preview5.webp\" alt=\"Espace SOMA\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n','Accueil','','inherit','closed','closed','','6-revision-v1','','','2026-04-11 16:26:55','2026-04-11 14:26:55','',6,'http://localhost:8090/?p=26',0,'revision','',0),
