textAlign\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"1.6rem\",\"letterSpacing\":\"0.08em\",\"textTransform\":\"uppercase\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"font-size:1.6rem;letter-spacing:0.08em;text-transform:uppercase\">Paiement en ligne sécurisé</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">Réglez votre séance en toute sécurité via Stripe.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#B8964E\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" style=\"background-color:#B8964E\" href=\"#\" target=\"_blank\" rel=\"noreferrer noopener\">Payer en ligne via Stripe</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#B8704C\",\"text\":\"#ffffff\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-text-color has-background\" style=\"color:#ffffff;background-color:#B8704C;padding-top:4rem;padding-bottom:4rem\"><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"},\"typography\":{\"fontSize\":\"1.1rem\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#ffffff;font-size:1.1rem\">Envie de réserver ? Choisissez votre soin et trouvez le créneau qui vous convient.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#B8704C\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#B8704C;background-color:#ffffff\">Prendre un rendez-vous</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n','Prestations & Rituels','','inherit','closed','closed','','7-revision-v1','','','2026-04-11 16:27:13','2026-04-11 14:27:13','',7,'http://localhost:8090/?p=27',0,'revision','',0),
(28,0,'2026-04-11 16:27:38','2026-04-11 14:27:38','<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"6rem\",\"bottom\":\"3rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background soma-page-header\" style=\"background-color:#F5F0EB;padding-top:6rem;padding-bottom:3rem\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":1,\"style\":{\"typography\":{\"fontSize\":\"2.5rem\",\"letterSpacing\":\"0.1em\",\"textTransform\":\"uppercase\"}}} -->\n<h1 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2.5rem;letter-spacing:0.1em;text-transform:uppercase\">Atelier SOMA</h1>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">Deux espaces, une même philosophie du bien-être et de la reconnexion à soi.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"padding-top:5rem;padding-bottom:5rem\"><!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"45%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:45%\"><!-- wp:image {\"sizeSlug\":\"large\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"/wp-content/themes/soma-avignon/img/preview4.webp\" alt=\"Bol tibétain SOMA\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"sizeSlug\":\"large\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"/wp-content/themes/soma-avignon/img/preview2.webp\" alt=\"Soin holistique\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"55%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:55%\"><!-- wp:heading {\"style\":{\"typography\":{\"fontSize\":\"1.9rem\"}}} -->\n<h2 class=\"wp-block-heading\" style=\"font-size:1.9rem\">L Atelier SOMA — Boulogne-Billancourt</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">L Atelier SOMA, fondé à Boulogne-Billancourt, est un espace de soin holistique dédié au bien-être. Porté par Géraldine Dupuis, thérapeute holistique et doula, c est un lieu de transformation et de reconnexion à soi.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">Notre antenne à Avignon s inscrit dans cette même philosophie : offrir un espace chaleureux où chaque soin est pensé pour répondre à vos besoins profonds. Nous partageons les mêmes valeurs de bienveillance, d authenticité et d approche holistique.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">Ensemble, nous proposons un accompagnement complet alliant massage énergétique crânien, soins prénataux et postnataux, et coiffure holistique.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:4rem;padding-bottom:4rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"1.6rem\",\"letterSpacing\":\"0.08em\",\"textTransform\":\"uppercase\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"font-size:1.6rem;letter-spacing:0.08em;text-transform:uppercase\">Nos valeurs partagées</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"2rem\"}}} -->\n<p class=\"has-text-align-center\" style=\"font-size:2rem\">✧</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n<h4 class=\"wp-block-heading has-text-align-center\">Bienveillance</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"},\"typography\":{\"fontSize\":\"0.9rem\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52;font-size:0.9rem\">Chaque personne est accueillie avec douceur et sans jugement.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"2rem\"}}} -->\n<p class=\"has-text-align-center\" style=\"font-size:2rem\">❋</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n<h4 class=\"wp-block-heading has-text-align-center\">Holistique</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"},\"typography\":{\"fontSize\":\"0.9rem\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52;font-size:0.9rem\">Corps, esprit et émotions pris en compte dans leur globalité.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"2rem\"}}} -->\n<p class=\"has-text-align-center\" style=\"font-size:2rem\">◈</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n<h4 class=\"wp-block-heading has-text-align-center\">Authenticité</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"},\"typography\":{\"fontSize\":\"0.9rem\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52;font-size:0.9rem\">Des soins sincères et adaptés à votre parcours unique.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#B8704C\",\"text\":\"#ffffff\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-text-color has-background\" style=\"color:#ffffff;background-color:#B8704C;padding-top:4rem;padding-bottom:4rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"},\"typography\":{\"fontSize\":\"1.6rem\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff;font-size:1.6rem\">Découvrez l Atelier SOMA</h2>\n<!-- /wp:heading -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#B8704C\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#B8704C;background-color:#ffffff\" href=\"https://www.ateliersoma.fr/\" target=\"_blank\" rel=\"noreferrer noopener\">Visiter ateliersoma.fr</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n','Collaboration Atelier SOMA','','inherit','closed','closed','','8-revision-v1','','','2026-04-11 16:27:38','2026-04-11 14:27:38','',8,'http://localhost:8090/?p=28',0,'revision','',0),
(29,0,'2026-04-11 16:27:54','2026-04-11 14:27:54','<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"6rem\",\"bottom\":\"3rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background soma-page-header\" style=\"background-color:#F5F0EB;padding-top:6rem;padding-bottom:3rem\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":1,\"style\":{\"typography\":{\"fontSize\":\"2.5rem\",\"letterSpacing\":\"0.1em\",\"textTransform\":\"uppercase\"}}} -->\n<h1 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2.5rem;letter-spacing:0.1em;text-transform:uppercase\">Contact</h1>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"style\":{\"color\":{\"background\":\"#C4A882\"}},\"className\":\"is-style-wide\"} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center\" style=\"color:#6B5D52\">N hésitez pas à nous contacter pour toute question ou prise de rendez-vous.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"padding-top:4rem;padding-bottom:4rem\"><!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#B8704C\"},\"typography\":{\"fontSize\":\"1.2rem\"}}} -->\n<h3 class=\"wp-block-heading\" style=\"color:#B8704C;font-size:1.2rem\">Adresse</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">SOMA Avignon<br>Avignon, France</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#B8704C\"},\"typography\":{\"fontSize\":\"1.2rem\"},\"spacing\":{\"margin\":{\"top\":\"2rem\"}}}} -->\n<h3 class=\"wp-block-heading\" style=\"color:#B8704C;font-size:1.2rem;margin-top:2rem\">Téléphone</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">06 00 00 00 00</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#B8704C\"},\"typography\":{\"fontSize\":\"1.2rem\"},\"spacing\":{\"margin\":{\"top\":\"2rem\"}}}} -->\n<h3 class=\"wp-block-heading\" style=\"color:#B8704C;font-size:1.2rem;margin-top:2rem\">Email</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p style=\"color:#6B5D52\">contact@soma-avignon.fr</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#B8704C\"},\"typography\":{\"fontSize\":\"1.2rem\"}}} -->\n<h3 class=\"wp-block-heading\" style=\"color:#B8704C;font-size:1.2rem\">Horaires</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table {\"className\":\"soma-horaires-table\"} -->\n<figure class=\"wp-block-table soma-horaires-table\"><table class=\"has-fixed-layout\"><tbody><tr><td>Lundi</td><td>09h30 – 17h30</td></tr><tr><td>Mardi</td><td>09h30 – 17h30</td></tr><tr><td>Mercredi</td><td>09h30 – 17h30</td></tr><tr><td>Jeudi</td><td>09h30 – 17h30</td></tr><tr><td>Vendredi</td><td>09h30 – 17h30</td></tr><tr><td>Samedi</td><td>Fermé</td></tr><tr><td>Dimanche</td><td>Fermé</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"color\":{\"text\":\"#B8704C\"},\"typography\":{\"fontSize\":\"1.2rem\"},\"spacing\":{\"margin\":{\"top\":\"2rem\"}}}} -->\n<h3 class=\"wp-block-heading\" style=\"color:#B8704C;font-size:1.2rem;margin-top:2rem\">