(41,1,'2026-04-11 16:49:59','2026-04-11 14:49:59','<!-- wp:cover {\"url\":\"http://localhost:8090/wp-content/uploads/2026/04/preview5-768x1024.webp\",\"id\":36,\"dimRatio\":50,\"customOverlayColor\":\"#777259\",\"isUserOverlayColor\":false,\"minHeight\":75,\"minHeightUnit\":\"vh\",\"sizeSlug\":\"large\",\"className\":\"is-dark soma-hero\",\"style\":{\"color\":{\"background\":\"#3D3029\"}}} -->\n<div class=\"wp-block-cover is-dark soma-hero has-background\" style=\"background-color:#3D3029;min-height:75vh\"><img class=\"wp-block-cover__image-background wp-image-36 size-large\" alt=\"\" src=\"http://localhost:8090/wp-content/uploads/2026/04/preview5-768x1024.webp\" data-object-fit=\"cover\"/><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim\" style=\"background-color:#777259\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":1,\"style\":{\"typography\":{\"fontSize\":\"2.8rem\",\"letterSpacing\":\"0.06em\"},\"color\":{\"text\":\"#ffffff\"}}} -->\n<h1 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff;font-size:2.8rem;letter-spacing:0.06em\">SOMA AVIGNON</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffffcc\"},\"typography\":{\"fontSize\":\"1.1rem\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#ffffffcc;font-size:1.1rem\"><p class=\"has-text-align-center\" style=\"color:#ffffffcc;font-size:1.1rem\">Massage énergétique crânien &amp; Coiffure<br>Un espace de soin et de bien-être à Avignon</p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#B8704C\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" href=\"/prestations/\" style=\"background-color:#B8704C\">Consulter nos soins</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"className\":\"is-style-outline\",\"style\":{\"color\":{\"text\":\"#ffffff\"},\"border\":{\"color\":\"#ffffff\",\"width\":\"2px\"}}} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link has-text-color has-border-color wp-element-button\" style=\"border-color:#ffffff;border-width:2px;color:#ffffff\">Prendre un rendez-vous</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div></div>\n<!-- /wp:cover -->\n\n<p><!-- HERO BANNIERE — style ateliersoma : titre centré sur image pleine largeur --></p>\n\n<p><!-- PRÉSENTATION — 2 images côte à côte + texte descriptif comme ateliersoma --></p>\n\n<!-- wp:group {\"className\":\"soma-intro\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-intro has-white-background-color has-background\" style=\"padding-top:5rem;padding-bottom:5rem\"><!-- wp:columns {\"verticalAlignment\":\"top\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-top\"><!-- wp:column {\"verticalAlignment\":\"top\",\"width\":\"45%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top\" style=\"flex-basis:45%\"><!-- wp:gallery {\"columns\":2,\"linkTo\":\"none\",\"sizeSlug\":\"medium\"} -->\n<figure class=\"wp-block-gallery has-nested-images columns-2 is-cropped\"><!-- wp:image {\"sizeSlug\":\"medium\"} -->\n<figure class=\"wp-block-image size-medium\"><img src=\"/wp-content/themes/soma-avignon/img/preview.webp\" alt=\"Massage crânien\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"sizeSlug\":\"medium\"} -->\n<figure class=\"wp-block-image size-medium\"><img src=\"/wp-content/themes/soma-avignon/img/preview3.webp\" alt=\"Soin énergétique\"/></figure>\n<!-- /wp:image --></figure>\n<!-- /wp:gallery --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"top\",\"width\":\"55%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top\" style=\"flex-basis:55%\"><!-- wp:heading {\"style\":{\"typography\":{\"fontSize\":\"1.9rem\"}}} -->\n<h2 class=\"wp-block-heading\" style=\"font-size:1.9rem\">SOMA : un espace de soin, de transformation et de reconnexion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bienvenue chez SOMA Avignon, un lieu dédié au bien-être holistique où chaque soin est pensé pour répondre à vos besoins profonds. Praticienne en massage énergétique crânien et coiffeuse, je vous accueille dans un espace chaleureux au coeur d Avignon.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Mes prestations s articulent autour de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Massage énergétique crânien</strong> — libération des tensions, rééquilibrage énergétique</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Massage prénatal</strong> — accompagnement doux de la grossesse</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Massage postnatal</strong> — reconnexion et récupération après l accouchement</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Coiffure holistique</strong> — prendre soin de soi dans sa globalité</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Chaque séance est un moment unique de détente et de reconnexion à soi, dans le respect et la bienveillance.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<p><!-- SERVICES — Grille de cartes 2x2 comme ateliersoma \"Soins holistiques et rituels\" --></p>\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:5rem;padding-bottom:5rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"2rem\",\"letterSpacing\":\"0.08em\",\"textTransform\":\"uppercase\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2rem;letter-spacing:0.08em;text-transform:uppercase\">Soins holistiques &amp; rituels</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"className\":\"is-style-wide\",\"style\":{\"color\":{\"background\":\"#C4A882\"}}} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:shortcode -->\n[soma_prestations limit=\"4\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:group -->\n\n<p><!-- LA CARTE — Section tarifs comme ateliersoma --></p>\n\n<!-- wp:group {\"className\":\"soma-carte-section\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-carte-section has-white-background-color has-background\" style=\"padding-top:5rem;padding-bottom:5rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"2.2rem\",\"letterSpacing\":\"0.12em\",\"textTransform\":\"uppercase\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2.2rem;letter-spacing:0.12em;text-transform:uppercase\">La Carte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"className\":\"is-style-wide\",\"style\":{\"color\":{\"background\":\"#C4A882\"}}} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#6B5D52\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#6B5D52\"><p class=\"has-text-align-center\" style=\"color:#6B5D52\">Découvrez sans plus attendre notre carte de soins. Nous faisons en sorte de mobiliser tout notre savoir-faire pour des prestations de qualité.</p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#B8704C\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" href=\"/prestations/\" style=\"background-color:#B8704C\">Découvrez notre carte</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<p><!-- TÉMOIGNAGES — comme ateliersoma \"Nos clients témoignent\" --></p>\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:5rem;padding-bottom:5rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"2rem\",\"letterSpacing\":\"0.08em\",\"textTransform\":\"uppercase\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"font-size:2rem;letter-spacing:0.08em;text-transform:uppercase\">Nos client(e)s témoignent</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"className\":\"is-style-wide\",\"style\":{\"color\":{\"background\":\"#C4A882\"}}} -->\n<hr class=\"wp-block-separator has-text-color has-alpha-channel-opacity has-background is-style-wide\" style=\"background-color:#C4A882;color:#C4A882\"/>\n<!-- /wp:separator -->\n\n<!-- wp:shortcode -->\n[soma_temoignages limit=\"3\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:group -->\n\n<p><!-- CTA RENDEZ-VOUS — bandeau comme ateliersoma --></p>\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"4rem\",\"bottom\":\"4rem\"}},\"color\":{\"background\":\"#B8704C\",\"text\":\"#ffffff\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-text-color has-background\" style=\"color:#ffffff;background-color:#B8704C;padding-top:4rem;padding-bottom:4rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffff\"},\"typography\":{\"fontSize\":\"1.8rem\"}}} -->\n<h2 class=\"wp-block-heading has-text-align-center\" style=\"color:#ffffff;font-size:1.8rem\">Prêt(e) à prendre soin de vous ?</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#ffffffcc\"}}} -->\n<p class=\"has-text-align-center has-text-color\" style=\"color:#ffffffcc\"><p class=\"has-text-align-center\" style=\"color:#ffffffcc\">Réservez votre séance en ligne ou appelez-nous directement.</p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"style\":{\"color\":{\"background\":\"#ffffff\",\"text\":\"#B8704C\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-color has-background wp-element-button\" style=\"color:#B8704C;background-color:#ffffff\">Prendre un rendez-vous</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"style\":{\"color\":{\"background\":\"#B8964E\"}}} -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" href=\"#\" style=\"background-color:#B8964E\" target=\"_blank\" rel=\"noreferrer noopener\">Payer en ligne</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group -->\n\n<p><!-- COLLABORATION ATELIER SOMA — teaser --></p>\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-white-background-color has-background\" style=\"padding-top:5rem;padding-bottom:5rem\"><!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"ver