lor\":\"#ffffff\",\"width\":\"2px\"}}} -->\n<div class=\"wp-block-button is-style-outline\"><a class=\"wp-block-button__link has-text-color has-border-color wp-element-button\" style=\"border-color:#ffffff;border-width:2px;color:#ffffff\">Prendre un rendez-vous</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div></div>\n<!-- /wp:cover -->\n\n<p><!-- HERO BANNIERE — style ateliersoma : titre centré sur image pleine largeur --></p>\n\n<p><!-- PRÉSENTATION — 2 images côte à côte + texte descriptif comme ateliersoma --></p>\n\n<!-- wp:group {\"className\":\"soma-intro\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}}},\"backgroundColor\":\"white\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group soma-intro has-white-background-color has-background\" style=\"padding-top:5rem;padding-bottom:5rem\"><!-- wp:columns {\"verticalAlignment\":\"top\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-top\"><!-- wp:column {\"verticalAlignment\":\"top\",\"width\":\"45%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top\" style=\"flex-basis:45%\"><!-- wp:gallery {\"columns\":2,\"linkTo\":\"none\",\"sizeSlug\":\"medium\"} -->\n<figure class=\"wp-block-gallery has-nested-images columns-2 is-cropped\"><!-- wp:image {\"sizeSlug\":\"medium\"} -->\n<figure class=\"wp-block-image size-medium\"><img src=\"/wp-content/themes/soma-avignon/img/preview.webp\" alt=\"Massage crânien\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"sizeSlug\":\"medium\"} -->\n<figure class=\"wp-block-image size-medium\"><img src=\"/wp-content/themes/soma-avignon/img/preview3.webp\" alt=\"Soin énergétique\"/></figure>\n<!-- /wp:image --></figure>\n<!-- /wp:gallery --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"top\",\"width\":\"55%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top\" style=\"flex-basis:55%\"><!-- wp:heading {\"style\":{\"typography\":{\"fontSize\":\"1.9rem\"}}} -->\n<h2 class=\"wp-block-heading\" style=\"font-size:1.9rem\">SOMA : un espace de soin, de transformation et de reconnexion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bienvenue chez SOMA Avignon, un lieu dédié au bien-être holistique où chaque soin est pensé pour répondre à vos besoins profonds. Praticienne en massage énergétique crânien et coiffeuse, je vous accueille dans un espace chaleureux au coeur d Avignon.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Mes prestations s articulent autour de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Massage énergétique crânien</strong> — libération des tensions, rééquilibrage énergétique</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Massage prénatal</strong> — accompagnement doux de la grossesse</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Massage postnatal</strong> — reconnexion et récupération après l accouchement</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Coiffure holistique</strong> — prendre soin de soi dans sa globalité</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Chaque séance est un moment unique de détente et de reconnexion à soi, dans le respect et la bienveillance.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<p><!-- SERVICES — Grille de cartes 2x2 comme ateliersoma \"Soins holistiques et rituels\" --></p>\n\n<!-- wp:group {\"style\":{\"spacing\":{\"padding\":{\"top\":\"5rem\",\"bottom\":\"5rem\"}},\"color\":{\"background\":\"#F5F0EB\"}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group has-background\" style=\"background-color:#F5F0EB;padding-top:5rem;padding-bottom:5rem\"><!-- wp:heading {\"textAlign\":\"center\",\"style\":{\"typography\":{\"fontSize\":\"2rem\",\"letterSpacing\":\"0.08em\",\"textTransform\":\"uppercase\"}}} -->\n<h2 class=\"